export interface GitHubRepo {
  id: number;
  name: string;
  full_name: string;
  html_url: string;
  description: string | null;
  language: string | null;
  stargazers_count: number;
  forks_count: number;
  updated_at: string;
  topics: string[];
  clone_url: string;
  default_branch: string;
}

export interface CoffeeAnalysis {
  roast: string;
  tastingNotes: string;
}

import { GitHubRepo, GitHubUser } from '../types';

const BASE_URL = 'https://api.github.com';
const USERNAME = 'pro-grammer-SD';

export const fetchProfile = async (): Promise<GitHubUser> => {
  const response = await fetch(`${BASE_URL}/users/${USERNAME}`);
  if (!response.ok) throw new Error('Failed to fetch user profile');
  return response.json();
};

export const fetchRepos = async (): Promise<GitHubRepo[]> => {
  const response = await fetch(`${BASE_URL}/users/${USERNAME}/repos?sort=updated&per_page=100`);
  if (!response.ok) throw new Error('Failed to fetch repositories');
  const repos = await response.json();
  // Filter out forks if desired, or keep them. We keep them as per "all public repos"
  return repos;
};

export const fetchReadme = async (repoName: string, branch: string = 'main'): Promise<string | null> => {
  // Try main, then master
  const branches = [branch, 'master'];

  for (const b of branches) {
    const url = `https://raw.githubusercontent.com/${USERNAME}/${repoName}/${b}/README.md`;
    try {
      const response = await fetch(url);
      if (response.ok) {
        return await response.text();
      }
    } catch (e) {
      console.warn(`Could not fetch README for ${repoName} on branch ${b}`);
    }
  }
  return null;
};

// A "client-side AI" heuristic since we don't have a backend to run a real LLM for every repo
export const analyzeRepo = (repo: GitHubRepo): { roast: string; description: string } => {
  const lang = repo.language || 'Unknown';
  const size = repo.stargazers_count + repo.forks_count;

  let roast = 'Light Roast';
  if (size > 10) roast = 'Medium Roast';
  if (size > 50) roast = 'Dark Roast';
  if (size > 100) roast = 'Double Espresso Shot';

  const descriptions = [
    `A distinct blend of ${lang} notes with a smooth finish.`,
    `Brewed with passion using ${lang}. Best served hot.`,
    `A complex ${lang} origin with hints of innovation.`,
    `An experimental batch involving ${lang} and caffeine.`,
    `Bold ${lang} flavor profile with a robust architecture.`
  ];

  // Deterministic "random" based on repo ID
  const descIndex = repo.id % descriptions.length;

  return {
    roast,
    description: descriptions[descIndex]
  };
};

