import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Star, GitFork, GitBranch, ChevronDown, ChevronUp, Copy, Check } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { GitHubRepo } from '../types';
import { fetchReadme, analyzeRepo } from '../services/githubService';

interface RepoCardProps {
  repo: GitHubRepo;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo }) => {
  const [expanded, setExpanded] = useState(false);
  const [readme, setReadme] = useState<string | null>(null);
  const [loadingReadme, setLoadingReadme] = useState(false);
  const [copied, setCopied] = useState(false);

  const analysis = analyzeRepo(repo);

  const toggleExpand = async () => {
    if (!expanded && !readme) {
      setLoadingReadme(true);
      const content = await fetchReadme(repo.name, repo.default_branch);
      setReadme(content || 'No README found for this repository.');
      setLoadingReadme(false);
    }
    setExpanded(!expanded);
  };

  const copyClone = () => {
    navigator.clipboard.writeText(`git clone ${repo.clone_url}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <motion.div 
      layout
      className="bg-white rounded-xl shadow-sm border border-coffee-200 hover:shadow-md hover:border-coffee-400 transition-all duration-300 overflow-hidden flex flex-col"
    >
      <div className="p-6 flex flex-col h-full">
        {/* Header */}
        <div className="flex justify-between items-start mb-2">
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-1">
                <GitBranch size={16} className="text-coffee-500" />
                <h3 className="font-display font-bold text-xl text-coffee-800 break-all">{repo.name}</h3>
            </div>
            {repo.language && (
                <span className="inline-block px-2 py-0.5 bg-coffee-100 text-coffee-700 text-xs rounded-full font-semibold">
                    {repo.language}
                </span>
            )}
          </div>
          <div className="flex gap-3 text-coffee-600">
             <div className="flex items-center gap-1 text-sm">
                 <Star size={16} className="fill-coffee-200" />
                 <span>{repo.stargazers_count}</span>
             </div>
             <div className="flex items-center gap-1 text-sm">
                 <GitFork size={16} />
                 <span>{repo.forks_count}</span>
             </div>
          </div>
        </div>

        {/* Description */}
        <p className="text-coffee-600 mb-4 text-sm leading-relaxed line-clamp-3">
            {repo.description || "No description provided."}
        </p>

        {/* AI/Coffee Analysis */}
        <div className="mt-auto bg-coffee-50 p-3 rounded-lg border border-coffee-100 mb-4">
            <div className="flex justify-between items-center mb-1">
                <span className="text-xs font-bold text-coffee-400 uppercase tracking-wide">Blend Analysis</span>
                <span className="text-xs font-bold text-coffee-700">{analysis.roast}</span>
            </div>
            <p className="text-sm italic text-coffee-800">"{analysis.description}"</p>
        </div>

        {/* Action Bar */}
        <div className="flex items-center justify-between border-t border-coffee-100 pt-4 mt-2">
            <div className="flex items-center gap-2">
                <button 
                    onClick={copyClone}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-coffee-200 text-coffee-700 rounded-md text-xs hover:bg-coffee-50 transition-colors"
                    title="Copy Clone Command"
                >
                    {copied ? <Check size={14} /> : <Copy size={14} />}
                    <span className="font-mono">Clone</span>
                </button>
            </div>

            <button 
                onClick={toggleExpand}
                className="flex items-center gap-1 text-coffee-600 hover:text-coffee-800 text-sm font-medium transition-colors"
            >
                {expanded ? 'Close Specs' : 'Read Specs'}
                {expanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
            </button>
        </div>
      </div>

      {/* Expanded Content (README) */}
      <AnimatePresence>
        {expanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="bg-coffee-50 border-t border-coffee-200"
          >
            <div className="p-6">
                {loadingReadme ? (
                    <div className="flex items-center justify-center py-8 text-coffee-400 gap-2">
                         <div className="w-4 h-4 border-2 border-coffee-400 border-t-transparent rounded-full animate-spin"></div>
                         <span className="text-sm">Grinding beans...</span>
                    </div>
                ) : (
                    <article className="prose prose-sm prose-stone max-w-none prose-headings:font-display prose-headings:text-coffee-800 prose-a:text-coffee-600 prose-code:text-coffee-700 prose-pre:bg-white prose-pre:border prose-pre:border-coffee-200">
                        <ReactMarkdown>{readme || ''}</ReactMarkdown>
                    </article>
                )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default RepoCard;

