export default ProfileHero;

import React, { useState, useMemo } from 'react';
import { Search, Filter } from 'lucide-react';
import { GitHubRepo } from '../types';
import RepoCard from './RepoCard';

interface RepoGridProps {
  repos: GitHubRepo[];
}

const RepoGrid: React.FC<RepoGridProps> = ({ repos }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [languageFilter, setLanguageFilter] = useState('All');

  // Extract unique languages
  const languages = useMemo(() => {
    const langs = new Set(repos.map(r => r.language).filter(Boolean));
    return ['All', ...Array.from(langs).sort()];
  }, [repos]);

  const filteredRepos = useMemo(() => {
    return repos.filter(repo => {
      const matchesSearch = repo.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            (repo.description && repo.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesLang = languageFilter === 'All' || repo.language === languageFilter;
      return matchesSearch && matchesLang;
    });
  }, [repos, searchTerm, languageFilter]);

  return (
    <section id="repos" className="py-16 bg-white rounded-t-[3rem] shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.1)] min-h-screen">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
            <h2 className="text-3xl font-display font-bold text-coffee-900 flex items-center gap-3">
                <span className="bg-coffee-100 p-2 rounded-lg text-2xl">📦</span>
                The Code Pantry
            </h2>

            {/* Controls */}
            <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                {/* Search */}
                <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search size={18} className="text-coffee-400 group-focus-within:text-coffee-600" />
                    </div>
                    <input
                        type="text"
                        placeholder="Search projects..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-10 pr-4 py-2 w-full sm:w-64 border border-coffee-200 rounded-xl focus:ring-2 focus:ring-coffee-400 focus:border-coffee-400 outline-none transition-all bg-coffee-50 placeholder-coffee-300 text-coffee-800"
                    />
                </div>

                {/* Filter */}
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Filter size={18} className="text-coffee-400" />
                    </div>
                    <select
                        value={languageFilter}
                        onChange={(e) => setLanguageFilter(e.target.value)}
                        className="pl-10 pr-8 py-2 w-full sm:w-48 border border-coffee-200 rounded-xl focus:ring-2 focus:ring-coffee-400 focus:border-coffee-400 outline-none transition-all bg-coffee-50 text-coffee-800 appearance-none cursor-pointer"
                    >
                        {languages.map(lang => (
                            <option key={lang} value={lang}>{lang}</option>
                        ))}
                    </select>
                </div>
            </div>
        </div>

        {filteredRepos.length === 0 ? (
            <div className="text-center py-20 text-coffee-400">
                <p className="text-xl">No blends found matching your taste.</p>
                <button 
                    onClick={() => { setSearchTerm(''); setLanguageFilter('All'); }}
                    className="mt-4 text-coffee-600 underline hover:text-coffee-800"
                >
                    Clear filters
                </button>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredRepos.map(repo => (
                    <RepoCard key={repo.id} repo={repo} />
                ))}
            </div>
        )}
      </div>
    </section>
  );
};

export default RepoGrid;

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { fetchProfile, fetchRepos } from './services/githubService';
import { GitHubUser, GitHubRepo } from './types';
import CoffeeLoader from './components/CoffeeLoader';
import Navbar from './components/Navbar';
import ProfileHero from './components/ProfileHero';
import RepoGrid from './components/RepoGrid';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<GitHubUser | null>(null);
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const init = async () => {
      // Minimum loading time of 4 seconds as requested for the experience
      const minLoadTime = new Promise(resolve => setTimeout(resolve, 4000));

      try {
        const [userData, reposData] = await Promise.all([
          fetchProfile(),
          fetchRepos(),
          minLoadTime // Wait for both data and timer
        ]);

        setUser(userData);
        setRepos(reposData);
      } catch (err) {
        console.error("Error loading profile:", err);
        setError("Could not load GitHub data. Rate limit might be exceeded.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, []);

  return (
    <>
      <AnimatePresence mode="wait">
        {loading && (
            <motion.div 
                key="loader"
                exit={{ opacity: 0, y: -20 }}
                transition={{ duration: 0.5 }}
                className="fixed inset-0 z-50"
            >
                <CoffeeLoader />
            </motion.div>
        )}
      </AnimatePresence>

      {!loading && !error && user && (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.8 }}
            className="min-h-screen flex flex-col"
        >
          <Navbar user={user} />

          <main className="flex-grow">
            <ProfileHero user={user} />
            <RepoGrid repos={repos} />
          </main>

          <footer className="bg-white py-8 border-t border-coffee-200 mt-auto">
            <div className="max-w-7xl mx-auto px-4 text-center text-coffee-500 text-sm">
              <p>&copy; {new Date().getFullYear()} {user.name}. Brewed with React & Coffee.</p>
            </div>
          </footer>
        </motion.div>
      )}

      {error && !loading && (
        <div className="min-h-screen flex flex-col items-center justify-center p-4 text-center">
            <div className="text-6xl mb-4">☕💔</div>
            <h1 className="text-2xl font-bold text-coffee-900 mb-2">Out of Coffee Beans</h1>
            <p className="text-coffee-600">{error}</p>
