import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Star, GitFork, GitBranch, ChevronDown, ChevronUp, Copy, Check, Pin } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { GitHubRepo } from '../types';
import { fetchReadme, analyzeRepo } from '../services/githubService';

interface RepoCardProps {
  repo: GitHubRepo;
  isPinned?: boolean;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, isPinned = false }) => {
  const [expanded, setExpanded] = useState(false);
  const [readme, setReadme] = useState<string | null>(null);
  const [loadingReadme, setLoadingReadme] = useState(false);
  const [copied, setCopied] = useState(false);

  const analysis = analyzeRepo(repo);

  const toggleExpand = async () => {
    if (!expanded && !readme) {
      setLoadingReadme(true);
      const content = await fetchReadme(repo.name, repo.default_branch);
      setReadme(content || 'No README found for this repository.');
      setLoadingReadme(false);
    }
    setExpanded(!expanded);
  };

  const copyClone = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(`git clone ${repo.clone_url}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const pinnedStyle = isPinned 
    ? "border-2 border-coffee-800 shadow-[4px_4px_0px_0px_rgba(111,69,59,1)] hover:translate-x-[2px] hover:translate-y-[2px] hover:shadow-[2px_2px_0px_0px_rgba(111,69,59,1)] bg-cream"
    : "border border-coffee-200 shadow-sm hover:shadow-md hover:border-coffee-400 bg-white";

  return (
    <motion.div 
      layout
      className={`rounded-xl transition-all duration-200 overflow-hidden flex flex-col relative ${pinnedStyle}`}
    >
        {isPinned && (
            <div className="absolute top-0 right-0 bg-coffee-800 text-white px-3 py-1 rounded-bl-xl z-20 flex items-center gap-1">
                <Pin size={12} className="fill-current" />
                <span className="text-xs font-bold uppercase tracking-wider">Signature</span>
            </div>
        )}

      <div className="p-6 flex flex-col h-full cursor-default">
        {/* Header */}
        <div className="flex justify-between items-start mb-2">
          <div className="flex-1 pr-8">
            <div className="flex items-center gap-2 mb-1">
                <GitBranch size={16} className={`${isPinned ? 'text-coffee-800' : 'text-coffee-500'}`} />
                <h3 className="font-display font-bold text-xl text-coffee-900 break-all">{repo.name}</h3>
            </div>
            {repo.language && (
                <span className={`inline-block px-2 py-0.5 text-xs rounded-full font-semibold ${isPinned ? 'bg-coffee-200 text-coffee-800' : 'bg-coffee-100 text-coffee-700'}`}>
                    {repo.language}
                </span>
            )}
          </div>
        </div>

        {/* Stats */}
        <div className="flex gap-4 text-coffee-700 mb-3 text-sm font-medium">
             <div className="flex items-center gap-1">
                 <Star size={16} className={`fill-coffee-300 ${isPinned ? 'text-coffee-600' : ''}`} />
                 <span>{repo.stargazers_count}</span>
             </div>
             <div className="flex items-center gap-1">
                 <GitFork size={16} />
                 <span>{repo.forks_count}</span>
             </div>
        </div>

        {/* Description */}
        <p className="text-coffee-700 mb-4 text-sm leading-relaxed line-clamp-3">
            {repo.description || "No description provided."}
        </p>

        {/* AI/Coffee Analysis */}
        <div className={`mt-auto p-3 rounded-lg border mb-4 ${isPinned ? 'bg-coffee-100 border-coffee-200' : 'bg-coffee-50 border-coffee-100'}`}>
            <div className="flex justify-between items-center mb-1">
                <span className="text-xs font-bold text-coffee-500 uppercase tracking-wide">Blend Analysis</span>
                <span className="text-xs font-bold text-coffee-800">{analysis.roast}</span>
            </div>
            <p className="text-sm italic text-coffee-800">"{analysis.description}"</p>
        </div>

        {/* Action Bar */}
        <div className={`flex items-center justify-between border-t pt-4 mt-2 ${isPinned ? 'border-coffee-200' : 'border-coffee-100'}`}>
            <div className="flex items-center gap-2">
                <button 
                    onClick={copyClone}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-coffee-200 text-coffee-700 rounded-md text-xs hover:bg-coffee-50 transition-colors shadow-sm"
                    title="Copy Clone Command"
                >
                    {copied ? <Check size={14} className="text-green-600" /> : <Copy size={14} />}
                    <span className="font-mono">Clone</span>
                </button>
            </div>

            <button 
                onClick={toggleExpand}
                className="flex items-center gap-1 text-coffee-700 hover:text-coffee-900 text-sm font-bold transition-colors"
            >
                {expanded ? 'Close Specs' : 'Read Specs'}
                {expanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
            </button>
        </div>
      </div>

      {/* Expanded Content (README) */}
      <AnimatePresence>
        {expanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="bg-white border-t border-coffee-200"
          >
            <div className="p-6">
                {loadingReadme ? (
                    <div className="flex items-center justify-center py-8 text-coffee-400 gap-2">
                         <div className="w-4 h-4 border-2 border-coffee-400 border-t-transparent rounded-full animate-spin"></div>
                         <span className="text-sm">Grinding beans...</span>
                    </div>
                ) : (
                    <div className="prose prose-sm prose-stone max-w-none prose-headings:font-display prose-headings:text-coffee-800 prose-a:text-coffee-600 prose-a:underline prose-code:text-coffee-800 prose-code:bg-coffee-50 prose-code:px-1 prose-code:rounded prose-pre:bg-coffee-900 prose-pre:text-coffee-50 prose-img:rounded-lg prose-img:shadow-md">
