import React, { useState, useMemo } from 'react';
import { Search, Filter, FlaskConical, Clock } from 'lucide-react';
import { GitHubRepo } from '../types';
import RepoCard from './RepoCard';

interface RepoGridProps {
  repos: GitHubRepo[];
}

const RepoGrid: React.FC<RepoGridProps> = ({ repos }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [languageFilter, setLanguageFilter] = useState('All');

  // Extract unique languages
  const languages = useMemo(() => {
    const langs = new Set(repos.map(r => r.language).filter(Boolean));
    return ['All', ...Array.from(langs).sort()];
  }, [repos]);

  // Separate Pinned (Top 3 by stars) and Others
  const { pinnedRepos, otherRepos } = useMemo(() => {
    // Sort all by stars desc
    const sorted = [...repos].sort((a, b) => b.stargazers_count - a.stargazers_count);
    return {
        pinnedRepos: sorted.slice(0, 3),
        otherRepos: sorted.slice(3)
    };
  }, [repos]);

  // Filtering logic applies to both (though pinned are usually kept visible or filtered differently, 
  // here we will filter both lists to respect user search)
  const filterRepo = (repo: GitHubRepo) => {
      const matchesSearch = repo.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            (repo.description && repo.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesLang = languageFilter === 'All' || repo.language === languageFilter;
      return matchesSearch && matchesLang;
  };

  const filteredPinned = pinnedRepos.filter(filterRepo);
  const filteredOthers = otherRepos.filter(filterRepo);

  const brewingProjects = [
    { title: "Espresso AI", desc: "A neural network that predicts the perfect grind size." },
    { title: "Latte Layouts", desc: "CSS framework based entirely on coffee art patterns." },
    { title: "Bean Counter", desc: "Blockchain-based inventory management for roasters." }
  ];

  return (
    <section id="repos" className="py-16 bg-white rounded-t-[3rem] shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.1)] min-h-screen relative z-10">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-6">
            <div>
                <h2 className="text-4xl font-display font-bold text-coffee-900 flex items-center gap-3">
                    <span className="bg-coffee-100 p-2 rounded-xl text-3xl shadow-sm">📦</span>
                    The Code Pantry
                </h2>
                <p className="mt-2 text-coffee-600">Freshly brewed open source contributions.</p>
            </div>

            {/* Controls */}
            <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                {/* Search */}
                <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search size={18} className="text-coffee-400 group-focus-within:text-coffee-600" />
                    </div>
                    <input
                        type="text"
                        placeholder="Search projects..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-10 pr-4 py-2 w-full sm:w-64 border border-coffee-200 rounded-xl focus:ring-2 focus:ring-coffee-400 focus:border-coffee-400 outline-none transition-all bg-coffee-50 placeholder-coffee-300 text-coffee-800 shadow-inner"
                    />
                </div>

                {/* Filter */}
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Filter size={18} className="text-coffee-400" />
                    </div>
                    <select
                        value={languageFilter}
                        onChange={(e) => setLanguageFilter(e.target.value)}
                        className="pl-10 pr-8 py-2 w-full sm:w-48 border border-coffee-200 rounded-xl focus:ring-2 focus:ring-coffee-400 focus:border-coffee-400 outline-none transition-all bg-coffee-50 text-coffee-800 appearance-none cursor-pointer shadow-inner"
                    >
                        {languages.map(lang => (
                            <option key={lang} value={lang}>{lang}</option>
                        ))}
                    </select>
                </div>
            </div>
        </div>

        {/* Signature Blends (Pinned) */}
        {filteredPinned.length > 0 && (
            <div className="mb-16">
                <h3 className="text-2xl font-display font-bold text-coffee-800 mb-6 flex items-center gap-2">
                    <Star className="fill-coffee-500 text-coffee-500" /> Signature Blends
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {filteredPinned.map(repo => (
                        <RepoCard key={repo.id} repo={repo} isPinned={true} />
                    ))}
                </div>
            </div>
        )}

        {/* Other Repos */}
        {filteredOthers.length > 0 && (
            <div className="mb-16">
                 <h3 className="text-xl font-display font-bold text-coffee-700 mb-6 flex items-center gap-2">
                    <FlaskConical className="text-coffee-400" /> Experimental Batches
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredOthers.map(repo => (
                        <RepoCard key={repo.id} repo={repo} />
                    ))}
                </div>
            </div>
        )}

        {/* No Results */}
        {filteredPinned.length === 0 && filteredOthers.length === 0 && (
            <div className="text-center py-20 text-coffee-400">
                <p className="text-xl">No blends found matching your taste.</p>
                <button 
                    onClick={() => { setSearchTerm(''); setLanguageFilter('All'); }}
                    className="mt-4 text-coffee-600 underline hover:text-coffee-800"
                >
                    Clear filters
                </button>
            </div>
        )}

        {/* Brewing Soon Section */}
        <div className="mt-20 border-t-2 border-dashed border-coffee-200 pt-16">
             <div className="text-center mb-10">
                <h2 className="text-3xl font-display font-bold text-coffee-800 inline-flex items-center gap-3">
                    <Clock className="text-coffee-500 animate-pulse" size={32} />
                    Brewing Soon
                </h2>
                <p className="text-coffee-500 mt-2">Experimental roasts currently in development.</p>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                {brewingProjects.map((proj, idx) => (
                    <div key={idx} className="bg-coffee-50 rounded-xl p-6 border border-coffee-100 flex flex-col items-center text-center opacity-80 hover:opacity-100 transition-opacity">
                        <div className="w-12 h-12 bg-coffee-200 rounded-full flex items-center justify-center mb-4">
                            <span className="text-2xl animate-bounce" style={{ animationDelay: `${idx * 0.2}s` }}>☕</span>
                        </div>
                        <h4 className="font-display font-bold text-lg text-coffee-800">{proj.title}</h4>
                        <p className="text-sm text-coffee-600 mt-2">{proj.desc}</p>
                        <div className="mt-4 text-xs font-bold text-coffee-400 uppercase tracking-widest bg-coffee-100 px-2 py-1 rounded">
                            Steeping...
                        </div>
                    </div>
                ))}
             </div>
        </div>
      </div>
    </section>
  );
};

export default RepoGrid;

import React, { useEffect, useState } from 'react';
import { motion, useAnimation } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { GitHubUser } from '../types';
import { fetchReadme } from '../services/githubService';

interface ProfileHeroProps {
  user: GitHubUser;
}

const ProfileHero: React.FC<ProfileHeroProps> = ({ user }) => {
  const [profileReadme, setProfileReadme] = useState<string | null>(null);
  const controls = useAnimation();
  const [easterEggActive, setEasterEggActive] = useState(false);

  useEffect(() => {
    const loadProfileReadme = async () => {
      const content = await fetchReadme(user.login, 'main');
      if (content) setProfileReadme(content);
      else {
           const contentMaster = await fetchReadme(user.login, 'master');
           setProfileReadme(contentMaster);
      }
    };
    loadProfileReadme();
  }, [user.login]);

  const triggerEasterEgg = async () => {
    if (easterEggActive) return;
    setEasterEggActive(true);

    // Play sound (using a simple oscillator for a 'clink' sound to avoid asset dependencies)
    try {
        const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
        if (AudioContext) {
            const ctx = new AudioContext();
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.type = 'sine';
            osc.frequency.setValueAtTime(800, ctx.currentTime);
            osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.1);

            gain.gain.setValueAtTime(0.3, ctx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);

            osc.connect(gain);
            gain.connect(ctx.destination);
            osc.start();
            osc.stop(ctx.currentTime + 0.5);
        }
    } catch (e) {
        console.log("Audio not supported or blocked");
    }

    // Animation sequence
    await controls.start({
        rotate: [0, -15, 15, -15, 15, 0],
        scale: [1, 1.2, 1.2, 1.2, 1],
        transition: { duration: 0.5 }
    });

    setEasterEggActive(false);
  };

  return (
    <section id="hero" className="relative pt-24 pb-12 sm:pt-32 sm:pb-20 overflow-hidden">
      {/* Background decorations */}
      <div className="absolute top-20 right-10 w-64 h-64 bg-coffee-100 rounded-full blur-3xl opacity-50 -z-10 animate-pulse"></div>
      <div className="absolute bottom-10 left-10 w-48 h-48 bg-orange-100 rounded-full blur-3xl opacity-50 -z-10"></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row items-center gap-12">

            {/* Left: Avatar & Stats */}
            <motion.div 
                initial={{ x: -50, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                transition={{ duration: 0.7 }}
                className="flex-shrink-0 text-center md:text-left"
            >
                <div className="relative inline-block group">
                    <img 
                        src={user.avatar_url} 
                        alt={user.name} 
                        className="w-48 h-48 rounded-full border-4 border-white shadow-xl object-cover"
                    />
                    <motion.div 
                        animate={controls}
                        onClick={triggerEasterEgg}
                        className="absolute bottom-4 right-4 bg-coffee-500 text-white p-2 rounded-full shadow-lg border-2 border-white cursor-pointer hover:bg-coffee-600 transition-colors z-10"
                        whileHover={{ scale: 1.1 }}
                    >
                        <span className="text-xl select-none">☕</span>
                    </motion.div>

                    {/* Steam particles for Easter Egg */}
                    {easterEggActive && (
                        <>
                            <motion.div initial={{ opacity: 0, y: 0 }} animate={{ opacity: 0, y: -50 }} transition={{ duration: 1 }} className="absolute -top-4 right-4 text-2xl">✨</motion.div>
                            <motion.div initial={{ opacity: 0, y: 0 }} animate={{ opacity: 0, y: -40 }} transition={{ duration: 1, delay: 0.1 }} className="absolute -top-2 right-8 text-xl">✨</motion.div>
                            <motion.div initial={{ opacity: 0, y: 0 }} animate={{ opacity: 0, y: -60 }} transition={{ duration: 1, delay: 0.2 }} className="absolute -top-6 right-0 text-xl">❤️</motion.div>
                        </>
                    )}
                </div>
                <h1 className="mt-6 text-4xl font-display font-bold text-coffee-900">{user.name || user.login}</h1>
                <p className="text-coffee-600 text-lg mt-2">@{user.login}</p>

                <div className="mt-6 flex flex-wrap justify-center md:justify-start gap-4">
                    <div className="bg-white/80 px-4 py-2 rounded-lg border border-coffee-100 shadow-sm text-center">
                        <span className="block font-bold text-coffee-800 text-xl">{user.public_repos}</span>
                        <span className="text-xs text-coffee-500 uppercase tracking-wide">Repos</span>
                    </div>
                    <div className="bg-white/80 px-4 py-2 rounded-lg border border-coffee-100 shadow-sm text-center">
                        <span className="block font-bold text-coffee-800 text-xl">{user.followers}</span>
                        <span className="text-xs text-coffee-500 uppercase tracking-wide">Followers</span>
                    </div>
                </div>
            </motion.div>

            {/* Right: Bio / README */}
            <motion.div 
                initial={{ x: 50, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                transition={{ duration: 0.7, delay: 0.2 }}
                className="flex-1 bg-white/60 backdrop-blur-sm rounded-2xl p-6 sm:p-8 shadow-sm border border-coffee-200 w-full"
            >
                {profileReadme ? (
                    <article className="prose prose-stone prose-sm sm:prose-base max-w-none prose-headings:font-display prose-headings:text-coffee-800 prose-a:text-coffee-600 prose-strong:text-coffee-700">
                        <ReactMarkdown remarkPlugins={[remarkGfm]}>{profileReadme}</ReactMarkdown>
                    </article>
                ) : (
                    <div>
                        <h2 className="text-2xl font-display font-bold text-coffee-800 mb-4">About Me</h2>
                        <p className="text-coffee-700 text-lg leading-relaxed">
                            {user.bio || "Just a developer who loves code and coffee. Currently building awesome things."}
                        </p>
                    </div>
                )}
            </motion.div>
        </div>
      </div>
    </section>
  );
};

