import React, { useState, useMemo } from 'react';
import { Search, Filter, FlaskConical, Clock, Star, ChevronDown, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { GitHubRepo } from '../types';
import RepoCard from './RepoCard';

interface RepoGridProps {
  repos: GitHubRepo[];
  pinnedRepos: GitHubRepo[];
}

const RepoGrid: React.FC<RepoGridProps> = ({ repos, pinnedRepos }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [languageFilter, setLanguageFilter] = useState('All');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  // Extract unique languages from all repos
  const languages = useMemo(() => {
    const langs = new Set([...repos, ...pinnedRepos].map(r => r.language).filter(Boolean));
    return ['All', ...Array.from(langs).sort()];
  }, [repos, pinnedRepos]);

  const filterRepo = (repo: GitHubRepo) => {
      const matchesSearch = repo.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            (repo.description && repo.description.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesLang = languageFilter === 'All' || repo.language === languageFilter;
      return matchesSearch && matchesLang;
  };

  const filteredPinned = pinnedRepos.filter(filterRepo);
  const filteredOthers = repos.filter(r => !pinnedRepos.some(p => p.name === r.name)).filter(filterRepo);

  const brewingProjects = [
    { title: "Espresso AI", desc: "A neural network that predicts the perfect grind size." },
    { title: "Latte Layouts", desc: "CSS framework based entirely on coffee art patterns." },
    { title: "Bean Counter", desc: "Blockchain-based inventory management for roasters." }
  ];

  return (
    <section id="repos" className="py-16 bg-white dark:bg-coffee-950 rounded-t-[3rem] shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.1)] min-h-screen relative z-10 transition-colors duration-500">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-6">
            <div>
                <h2 className="text-4xl font-display font-bold text-coffee-900 dark:text-coffee-100 flex items-center gap-3">
                    <span className="bg-coffee-100 dark:bg-coffee-800 p-2 rounded-xl text-3xl shadow-sm">📦</span>
                    The Code Pantry
                </h2>
                <p className="mt-2 text-coffee-600 dark:text-coffee-400">Freshly brewed open source contributions.</p>
            </div>

            {/* Controls */}
            <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto items-start sm:items-center">

                {/* Search */}
                <div className="relative group w-full sm:w-auto">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search size={18} className="text-coffee-400 group-focus-within:text-coffee-600 dark:group-focus-within:text-coffee-300" />
                    </div>
                    <input
                        type="text"
                        placeholder="Search projects..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-10 pr-4 py-2 w-full sm:w-64 border border-coffee-200 dark:border-coffee-700 rounded-xl focus:ring-2 focus:ring-coffee-400 focus:border-coffee-400 outline-none transition-all bg-coffee-50 dark:bg-coffee-900 placeholder-coffee-300 dark:placeholder-coffee-600 text-coffee-800 dark:text-coffee-200 shadow-inner"
                    />
                </div>

                {/* Animated Filter Button & Dropdown */}
                <div className="relative w-full sm:w-auto">
                    <button 
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className="flex items-center justify-between w-full sm:w-48 px-4 py-2 bg-coffee-50 dark:bg-coffee-900 border border-coffee-200 dark:border-coffee-700 rounded-xl text-coffee-800 dark:text-coffee-200 focus:outline-none hover:bg-coffee-100 dark:hover:bg-coffee-800 transition-colors"
                    >
                        <div className="flex items-center gap-2">
                            <Filter size={18} className="text-coffee-400" />
                            <span className="truncate">{languageFilter}</span>
                        </div>
                        {isFilterOpen ? <X size={16} /> : <ChevronDown size={16} />}
                    </button>

                    <AnimatePresence>
                        {isFilterOpen && (
                            <motion.div
                                initial={{ opacity: 0, y: -10, height: 0 }}
                                animate={{ opacity: 1, y: 0, height: 'auto' }}
                                exit={{ opacity: 0, y: -10, height: 0 }}
                                transition={{ duration: 0.2 }}
                                className="absolute top-full mt-2 w-full sm:w-48 bg-white dark:bg-coffee-900 border border-coffee-200 dark:border-coffee-700 rounded-xl shadow-lg z-30 overflow-hidden"
                            >
                                <div className="max-h-60 overflow-y-auto py-1 custom-scrollbar">
                                    {languages.map(lang => (
                                        <button
                                            key={lang}
                                            onClick={() => { setLanguageFilter(lang); setIsFilterOpen(false); }}
                                            className={`w-full text-left px-4 py-2 text-sm transition-colors hover:bg-coffee-50 dark:hover:bg-coffee-800 ${
                                                languageFilter === lang 
                                                ? 'text-coffee-800 dark:text-coffee-100 font-bold bg-coffee-50 dark:bg-coffee-800' 
                                                : 'text-coffee-600 dark:text-coffee-400'
                                            }`}
                                        >
                                            {lang}
                                        </button>
                                    ))}
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            </div>
        </div>

        {/* Signature Blends (Pinned) */}
        {filteredPinned.length > 0 && (
            <div className="mb-16">
                <h3 className="text-2xl font-display font-bold text-coffee-800 dark:text-coffee-200 mb-6 flex items-center gap-2">
                    <Star className="fill-coffee-500 text-coffee-500" /> Signature Blends
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {filteredPinned.map(repo => (
                        <RepoCard key={`pin-${repo.name}`} repo={repo} isPinned={true} />
                    ))}
                </div>
            </div>
        )}

        {/* Other Repos */}
        {filteredOthers.length > 0 && (
            <div className="mb-16">
                 <h3 className="text-xl font-display font-bold text-coffee-700 dark:text-coffee-300 mb-6 flex items-center gap-2">
                    <FlaskConical className="text-coffee-400" /> Experimental Batches
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredOthers.map(repo => (
                        <RepoCard key={repo.id} repo={repo} />
                    ))}
                </div>
            </div>
        )}

        {/* No Results */}
        {filteredPinned.length === 0 && filteredOthers.length === 0 && (
            <div className="text-center py-20 text-coffee-400 dark:text-coffee-600">
                <p className="text-xl">No blends found matching your taste.</p>
                <button 
                    onClick={() => { setSearchTerm(''); setLanguageFilter('All'); }}
                    className="mt-4 text-coffee-600 dark:text-coffee-300 underline hover:text-coffee-800 dark:hover:text-white"
                >
                    Clear filters
                </button>
            </div>
        )}

        {/* Brewing Soon Section */}
        <div className="mt-20 border-t-2 border-dashed border-coffee-200 dark:border-coffee-800 pt-16">
             <div className="text-center mb-10">
                <h2 className="text-3xl font-display font-bold text-coffee-800 dark:text-coffee-100 inline-flex items-center gap-3">
                    <Clock className="text-coffee-500 animate-pulse" size={32} />
                    Brewing Soon
                </h2>
                <p className="text-coffee-500 dark:text-coffee-400 mt-2">Experimental roasts currently in development.</p>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                {brewingProjects.map((proj, idx) => (
                    <div key={idx} className="bg-coffee-50 dark:bg-coffee-900 rounded-xl p-6 border border-coffee-100 dark:border-coffee-800 flex flex-col items-center text-center opacity-80 hover:opacity-100 transition-opacity">
                        <div className="w-12 h-12 bg-coffee-200 dark:bg-coffee-800 rounded-full flex items-center justify-center mb-4">
                            <span className="text-2xl animate-bounce" style={{ animationDelay: `${idx * 0.2}s` }}>☕</span>
                        </div>
                        <h4 className="font-display font-bold text-lg text-coffee-800 dark:text-coffee-200">{proj.title}</h4>
                        <p className="text-sm text-coffee-600 dark:text-coffee-400 mt-2">{proj.desc}</p>
                        <div className="mt-4 text-xs font-bold text-coffee-400 uppercase tracking-widest bg-coffee-100 dark:bg-coffee-800 px-2 py-1 rounded">
                            Steeping...
                        </div>
                    </div>
                ))}
             </div>
        </div>
      </div>
    </section>
  );
};

export default RepoGrid;

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { fetchProfile, fetchRepos, fetchPinnedRepos } from './services/githubService';
import { GitHubUser, GitHubRepo } from './types';
import CoffeeLoader from './components/CoffeeLoader';
import Navbar from './components/Navbar';
import ProfileHero from './components/ProfileHero';
import RepoGrid from './components/RepoGrid';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<GitHubUser | null>(null);
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [pinnedRepos, setPinnedRepos] = useState<GitHubRepo[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Theme State
  const [isDark, setIsDark] = useState(false);

  // Audio State
  const [isPlaying, setIsPlaying] = useState(false);

  useEffect(() => {
    // Check system preference
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
        setIsDark(true);
    }
  }, []);

  useEffect(() => {
    if (isDark) {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  useEffect(() => {
    const init = async () => {
      // Minimum loading time of 4 seconds as requested for the experience
      const minLoadTime = new Promise(resolve => setTimeout(resolve, 4000));

      try {
        const [userData, reposData, pinnedData] = await Promise.all([
          fetchProfile(),
          fetchRepos(),
          fetchPinnedRepos(),
          minLoadTime
        ]);

        setUser(userData);
        setRepos(reposData);
        setPinnedRepos(pinnedData);
      } catch (err) {
        console.error("Error loading profile:", err);
        setError("Could not load GitHub data. Rate limit might be exceeded.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, []);

  const toggleTheme = () => setIsDark(!isDark);
  const toggleMusic = () => setIsPlaying(!isPlaying);

  return (
    <>
        {/* Hidden Background Music */}
        <div className="hidden">
            {isPlaying && (
                <iframe 
                    width="1" 
                    height="1" 
                    src="https://www.youtube.com/embed/SHpQ77wDfYg?autoplay=1&loop=1&playlist=SHpQ77wDfYg&controls=0" 
                    title="LoFi Music" 
                    allow="autoplay; encrypted-media"
                ></iframe>
            )}
        </div>

      <AnimatePresence mode="wait">
        {loading && (
            <motion.div 
                key="loader"
                exit={{ opacity: 0, y: -20 }}
                transition={{ duration: 0.5 }}
                className="fixed inset-0 z-50 bg-coffee-50 dark:bg-coffee-950"
            >
                <CoffeeLoader />
            </motion.div>
        )}
      </AnimatePresence>

      {!loading && !error && user && (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.8 }}
            className="min-h-screen flex flex-col bg-coffee-50 dark:bg-coffee-950 transition-colors duration-500"
        >
          <Navbar 
            user={user} 
            isDark={isDark} 
            toggleTheme={toggleTheme} 
            isPlaying={isPlaying}
            toggleMusic={toggleMusic}
          />

          <main className="flex-grow">
            <ProfileHero user={user} />
            <RepoGrid repos={repos} pinnedRepos={pinnedRepos} />
          </main>

          <footer className="bg-white dark:bg-coffee-900 py-8 border-t border-coffee-200 dark:border-coffee-800 mt-auto transition-colors duration-500">
            <div className="max-w-7xl mx-auto px-4 text-center text-coffee-500 dark:text-coffee-400 text-sm">
              <p>&copy; {new Date().getFullYear()} {user.name}. Brewed with React & Coffee.</p>
            </div>
          </footer>
        </motion.div>
      )}

      {error && !loading && (
        <div className="min-h-screen flex flex-col items-center justify-center p-4 text-center bg-coffee-50 dark:bg-coffee-950 text-coffee-900 dark:text-coffee-100">
            <div className="text-6xl mb-4">☕💔</div>
            <h1 className="text-2xl font-bold mb-2">Out of Coffee Beans</h1>
            <p className="text-coffee-600 dark:text-coffee-400">{error}</p>
            <p className="text-xs text-coffee-400 dark:text-coffee-500 mt-4">Try refreshing in a few minutes.</p>
        </div>
      )}
    </>
  );
};

export default App;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Star, GitFork, GitBranch, ChevronDown, ChevronUp, Copy, Check, Pin } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import { GitHubRepo } from '../types';
import { fetchReadme, analyzeRepo } from '../services/githubService';

interface RepoCardProps {
  repo: GitHubRepo;
  isPinned?: boolean;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, isPinned = false }) => {
  const [expanded, setExpanded] = useState(false);
  const [readme, setReadme] = useState<string | null>(null);
  const [loadingReadme, setLoadingReadme] = useState(false);
  const [copied, setCopied] = useState(false);

  const analysis = analyzeRepo(repo);

  const toggleExpand = async () => {
    if (!expanded && !readme) {
      setLoadingReadme(true);
      const content = await fetchReadme(repo.name, repo.default_branch);
      setReadme(content || 'No README found for this repository.');
      setLoadingReadme(false);
    }
    setExpanded(!expanded);
  };

  const copyClone = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(`git clone ${repo.clone_url}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const pinnedStyle = isPinned 
    ? "border-2 border-coffee-800 dark:border-coffee-500 shadow-[4px_4px_0px_0px_rgba(111,69,59,1)] dark:shadow-[4px_4px_0px_0px_rgba(167,127,114,1)] bg-cream dark:bg-coffee-900"
    : "border border-coffee-200 dark:border-coffee-700 shadow-sm bg-white dark:bg-coffee-900";

  return (
    <motion.div 
      layout
      whileHover={{ 
        y: -5, 
        scale: 1.01,
        boxShadow: isPinned 
            ? "6px 6px 0px 0px rgba(111,69,59,1)" 
            : "0 10px 25px -5px rgba(138, 90, 77, 0.15)"
      }}
      transition={{ type: "spring", stiffness: 300, damping: 20 }}
      className={`rounded-xl overflow-hidden flex flex-col relative ${pinnedStyle}`}
    >
        {isPinned && (
            <div className="absolute top-0 right-0 bg-coffee-800 dark:bg-coffee-600 text-white px-3 py-1 rounded-bl-xl z-20 flex items-center gap-1">
                <Pin size={12} className="fill-current" />
                <span className="text-xs font-bold uppercase tracking-wider">Signature</span>
            </div>
        )}

      <div className="p-6 flex flex-col h-full cursor-default">
        {/* Header */}
        <div className="flex justify-between items-start mb-2">
          <div className="flex-1 pr-8">
            <div className="flex items-center gap-2 mb-1">
                <GitBranch size={16} className={`${isPinned ? 'text-coffee-800 dark:text-coffee-200' : 'text-coffee-500 dark:text-coffee-400'}`} />
                <h3 className="font-display font-bold text-xl text-coffee-900 dark:text-coffee-100 break-all">{repo.name}</h3>
            </div>
            {repo.language && (
                <span className={`inline-block px-2 py-0.5 text-xs rounded-full font-semibold ${isPinned ? 'bg-coffee-200 dark:bg-coffee-800 text-coffee-800 dark:text-coffee-200' : 'bg-coffee-100 dark:bg-coffee-800 text-coffee-700 dark:text-coffee-300'}`}>
                    {repo.language}
                </span>
            )}
          </div>
        </div>

        {/* Stats */}
        <div className="flex gap-4 text-coffee-700 dark:text-coffee-300 mb-3 text-sm font-medium">
             <div className="flex items-center gap-1">
                 <Star size={16} className={`fill-coffee-300 dark:fill-coffee-700 ${isPinned ? 'text-coffee-600 dark:text-coffee-400' : ''}`} />
                 <span>{repo.stargazers_count}</span>
             </div>
             <div className="flex items-center gap-1">
                 <GitFork size={16} />
                 <span>{repo.forks_count}</span>
             </div>
        </div>

        {/* Description */}
        <p className="text-coffee-700 dark:text-coffee-400 mb-4 text-sm leading-relaxed line-clamp-3">
            {repo.description || "No description provided."}
        </p>

        {/* AI/Coffee Analysis */}
        <div className={`mt-auto p-3 rounded-lg border mb-4 ${isPinned ? 'bg-coffee-100 dark:bg-coffee-800 border-coffee-200 dark:border-coffee-700' : 'bg-coffee-50 dark:bg-coffee-800 border-coffee-100 dark:border-coffee-700'}`}>
            <div className="flex justify-between items-center mb-1">
                <span className="text-xs font-bold text-coffee-500 dark:text-coffee-400 uppercase tracking-wide">Blend Analysis</span>
                <span className="text-xs font-bold text-coffee-800 dark:text-coffee-200">{analysis.roast}</span>
            </div>
            <p className="text-sm italic text-coffee-800 dark:text-coffee-300">"{analysis.description}"</p>
        </div>

        {/* Action Bar */}
        <div className={`flex items-center justify-between border-t pt-4 mt-2 ${isPinned ? 'border-coffee-200 dark:border-coffee-700' : 'border-coffee-100 dark:border-coffee-800'}`}>
            <div className="flex items-center gap-2">
                <button 
                    onClick={copyClone}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-white dark:bg-coffee-800 border border-coffee-200 dark:border-coffee-700 text-coffee-700 dark:text-coffee-200 rounded-md text-xs hover:bg-coffee-50 dark:hover:bg-coffee-700 transition-colors shadow-sm"
                    title="Copy Clone Command"
                >
                    {copied ? <Check size={14} className="text-green-600" /> : <Copy size={14} />}
                    <span className="font-mono">Clone</span>
                </button>
            </div>

            <button 
                onClick={toggleExpand}
                className="flex items-center gap-1 text-coffee-700 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white text-sm font-bold transition-colors group"
            >
                {expanded ? 'Close Specs' : 'Read Specs'}
                <motion.div
                    animate={{ rotate: expanded ? 180 : 0 }}
                    transition={{ type: "spring", stiffness: 200 }}
                >
                    <ChevronDown size={16} />
                </motion.div>
            </button>
        </div>
      </div>

      {/* Expanded Content (README) */}
      <AnimatePresence>
        {expanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ type: "spring", stiffness: 100, damping: 20 }}
            className="bg-white dark:bg-coffee-950 border-t border-coffee-200 dark:border-coffee-700 overflow-hidden"
          >
            <div className="p-6">
                {loadingReadme ? (
                    <div className="flex items-center justify-center py-8 text-coffee-400 gap-2">
                         <div className="w-4 h-4 border-2 border-coffee-400 border-t-transparent rounded-full animate-spin"></div>
                         <span className="text-sm">Grinding beans...</span>
                    </div>
                ) : (
                    <div className="prose prose-sm prose-stone dark:prose-invert max-w-none prose-headings:font-display prose-headings:text-coffee-800 dark:prose-headings:text-coffee-100 prose-a:text-coffee-600 dark:prose-a:text-coffee-300 prose-a:underline prose-code:text-coffee-800 dark:prose-code:text-coffee-200 prose-code:bg-coffee-50 dark:prose-code:bg-coffee-900 prose-code:px-1 prose-code:rounded prose-pre:bg-coffee-900 dark:prose-pre:bg-black prose-pre:text-coffee-50 prose-img:rounded-lg prose-img:shadow-md">
