import React, { useState, useEffect, useRef } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { fetchProfile, fetchRepos, fetchPinnedRepos } from './services/githubService';
import { GitHubUser, GitHubRepo } from './types';
import CoffeeLoader from './components/CoffeeLoader';
import Navbar from './components/Navbar';
import ProfileHero from './components/ProfileHero';
import RepoGrid from './components/RepoGrid';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<GitHubUser | null>(null);
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [pinnedRepos, setPinnedRepos] = useState<GitHubRepo[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Theme State
  const [isDark, setIsDark] = useState(false);

  // Audio State
  const [isPlaying, setIsPlaying] = useState(false);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    // Check system preference
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
        setIsDark(true);
    }
  }, []);

  useEffect(() => {
    if (isDark) {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  useEffect(() => {
    const init = async () => {
      // Minimum loading time of 4 seconds as requested for the experience
      const minLoadTime = new Promise(resolve => setTimeout(resolve, 4000));

      try {
        const [userData, reposData, pinnedData] = await Promise.all([
          fetchProfile(),
          fetchRepos(),
          fetchPinnedRepos(),
          minLoadTime
        ]);

        setUser(userData);
        setRepos(reposData);
        setPinnedRepos(pinnedData);
      } catch (err) {
        console.error("Error loading profile:", err);
        setError("Could not load GitHub data. Rate limit might be exceeded.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, []);

  const toggleTheme = () => setIsDark(!isDark);

  const toggleMusic = () => {
      if (iframeRef.current && iframeRef.current.contentWindow) {
          if (isPlaying) {
              iframeRef.current.contentWindow.postMessage('{"event":"command","func":"pauseVideo","args":""}', '*');
          } else {
              iframeRef.current.contentWindow.postMessage('{"event":"command","func":"playVideo","args":""}', '*');
          }
      }
      setIsPlaying(!isPlaying);
  };

  const handleIframeLoad = () => {
      // When iframe loads, set volume to 100
      if (iframeRef.current && iframeRef.current.contentWindow) {
          iframeRef.current.contentWindow.postMessage('{"event":"command","func":"setVolume","args":[100]}', '*');
      }
  };

  // Auto-play attempt on mount (may be blocked by browser)
  useEffect(() => {
     if (!loading && isPlaying && iframeRef.current && iframeRef.current.contentWindow) {
          iframeRef.current.contentWindow.postMessage('{"event":"command","func":"setVolume","args":[100]}', '*');
          iframeRef.current.contentWindow.postMessage('{"event":"command","func":"playVideo","args":""}', '*');
     }
  }, [loading, isPlaying]);

  return (
    <>
        {/* Hidden Background Music */}
        <div className="absolute opacity-0 pointer-events-none w-0 h-0 overflow-hidden">
            <iframe 
                ref={iframeRef}
                width="100%" 
                height="100%" 
                src={`https://www.youtube.com/embed/SHpQ77wDfYg?enablejsapi=1&autoplay=${isPlaying ? 1 : 0}&loop=1&playlist=SHpQ77wDfYg&controls=0`}
                title="LoFi Music" 
                allow="autoplay; encrypted-media"
                onLoad={handleIframeLoad}
            ></iframe>
        </div>

      <AnimatePresence mode="wait">
        {loading && (
            <motion.div 
                key="loader"
                exit={{ opacity: 0, y: -20 }}
                transition={{ duration: 0.5 }}
                className="fixed inset-0 z-50 bg-coffee-50 dark:bg-coffee-950"
            >
                <CoffeeLoader />
            </motion.div>
        )}
      </AnimatePresence>

      {!loading && !error && user && (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.8 }}
            className="min-h-screen flex flex-col bg-coffee-50 dark:bg-coffee-950 transition-colors duration-500"
        >
          <Navbar 
            user={user} 
            isDark={isDark} 
            toggleTheme={toggleTheme} 
            isPlaying={isPlaying}
            toggleMusic={toggleMusic}
          />

          <main className="flex-grow">
            <ProfileHero user={user} />
            <RepoGrid repos={repos} pinnedRepos={pinnedRepos} />
          </main>

          <footer className="bg-white dark:bg-coffee-900 py-8 border-t border-coffee-200 dark:border-coffee-800 mt-auto transition-colors duration-500">
            <div className="max-w-7xl mx-auto px-4 text-center text-coffee-500 dark:text-coffee-400 text-sm">
              <p>&copy; {new Date().getFullYear()} {user.name}. Brewed with React & Coffee.</p>
            </div>
          </footer>
        </motion.div>
      )}

      {error && !loading && (
        <div className="min-h-screen flex flex-col items-center justify-center p-4 text-center bg-coffee-50 dark:bg-coffee-950 text-coffee-900 dark:text-coffee-100">
            <div className="text-6xl mb-4">☕💔</div>
            <h1 className="text-2xl font-bold mb-2">Out of Coffee Beans</h1>
            <p className="text-coffee-600 dark:text-coffee-400">{error}</p>
            <p className="text-xs text-coffee-400 dark:text-coffee-500 mt-4">Try refreshing in a few minutes.</p>
        </div>
      )}
    </>
  );
};

export default App;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Star, GitFork, GitBranch, ChevronDown, ChevronUp, Copy, Check, Pin } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import { GitHubRepo } from '../types';
import { fetchReadme, analyzeRepo } from '../services/githubService';

interface RepoCardProps {
  repo: GitHubRepo;
  isPinned?: boolean;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, isPinned = false }) => {
  const [expanded, setExpanded] = useState(false);
  const [readme, setReadme] = useState<string | null>(null);
  const [loadingReadme, setLoadingReadme] = useState(false);
  const [copied, setCopied] = useState(false);

  const analysis = analyzeRepo(repo);

  const toggleExpand = async () => {
    if (!expanded && !readme) {
      setLoadingReadme(true);
      const content = await fetchReadme(repo.name, repo.default_branch);
      setReadme(content || 'No README found for this repository.');
      setLoadingReadme(false);
    }
    setExpanded(!expanded);
  };

  const copyClone = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(`git clone ${repo.clone_url}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const pinnedStyle = isPinned 
    ? "border-2 border-coffee-800 dark:border-coffee-500 shadow-[4px_4px_0px_0px_rgba(111,69,59,1)] dark:shadow-[4px_4px_0px_0px_rgba(167,127,114,1)] bg-cream dark:bg-coffee-900"
    : "border border-coffee-200 dark:border-coffee-700 shadow-sm bg-white dark:bg-coffee-900";

  return (
    <motion.div 
      layout
      whileHover={{ 
        y: -5, 
        scale: 1.01,
        boxShadow: isPinned 
            ? "6px 6px 0px 0px rgba(111,69,59,1)" 
            : "0 10px 25px -5px rgba(138, 90, 77, 0.15)"
      }}
      transition={{ type: "spring", stiffness: 300, damping: 20 }}
      className={`rounded-xl overflow-hidden flex flex-col relative ${pinnedStyle}`}
    >
        {isPinned && (
            <motion.div 
                className="absolute top-0 right-0 bg-coffee-800 dark:bg-coffee-600 text-white px-3 py-1 rounded-bl-xl z-20 flex items-center gap-1 shadow-sm"
                initial={{ opacity: 0.9 }}
                animate={{ opacity: 1 }}
                whileHover={{ scale: 1.05 }}
            >
                <Pin size={12} className="fill-current" />
                <span className="text-xs font-bold uppercase tracking-wider">Signature</span>
            </motion.div>
        )}

      <div className="p-6 flex flex-col h-full cursor-default">
        {/* Header */}
        <div className="flex justify-between items-start mb-2">
          <div className="flex-1 pr-8">
            <div className="flex items-center gap-2 mb-1">
                <GitBranch size={16} className={`${isPinned ? 'text-coffee-800 dark:text-coffee-200' : 'text-coffee-500 dark:text-coffee-400'}`} />
                <h3 className="font-display font-bold text-xl text-coffee-900 dark:text-coffee-100 break-all">{repo.name}</h3>
            </div>
            {repo.language && (
                <span className={`inline-block px-2 py-0.5 text-xs rounded-full font-semibold ${isPinned ? 'bg-coffee-200 dark:bg-coffee-800 text-coffee-800 dark:text-coffee-200' : 'bg-coffee-100 dark:bg-coffee-800 text-coffee-700 dark:text-coffee-300'}`}>
                    {repo.language}
                </span>
            )}
          </div>
        </div>

        {/* Stats with Animation */}
        <div className="flex gap-4 text-coffee-700 dark:text-coffee-300 mb-3 text-sm font-medium">
             <motion.div 
                className="flex items-center gap-1 cursor-help p-1 rounded hover:bg-coffee-50 dark:hover:bg-coffee-800 transition-colors"
                whileHover={{ scale: 1.15, y: -2 }}
                transition={{ type: "spring", stiffness: 400, damping: 10 }}
             >
                 <Star size={16} className={`fill-coffee-300 dark:fill-coffee-700 ${isPinned ? 'text-coffee-600 dark:text-coffee-400' : ''}`} />
                 <span className="font-mono">{repo.stargazers_count}</span>
             </motion.div>
             <motion.div 
                className="flex items-center gap-1 cursor-help p-1 rounded hover:bg-coffee-50 dark:hover:bg-coffee-800 transition-colors"
                whileHover={{ scale: 1.15, y: -2 }}
                transition={{ type: "spring", stiffness: 400, damping: 10 }}
             >
                 <GitFork size={16} />
                 <span className="font-mono">{repo.forks_count}</span>
             </motion.div>
        </div>

        {/* Description */}
        <p className="text-coffee-700 dark:text-coffee-400 mb-4 text-sm leading-relaxed line-clamp-3">
            {repo.description || "No description provided."}
        </p>

        {/* AI/Coffee Analysis */}
        <div className={`mt-auto p-3 rounded-lg border mb-4 ${isPinned ? 'bg-coffee-100 dark:bg-coffee-800 border-coffee-200 dark:border-coffee-700' : 'bg-coffee-50 dark:bg-coffee-800 border-coffee-100 dark:border-coffee-700'}`}>
            <div className="flex justify-between items-center mb-1">
                <span className="text-xs font-bold text-coffee-500 dark:text-coffee-400 uppercase tracking-wide">Blend Analysis</span>
                <span className="text-xs font-bold text-coffee-800 dark:text-coffee-200">{analysis.roast}</span>
            </div>
            <p className="text-sm italic text-coffee-800 dark:text-coffee-300">"{analysis.description}"</p>
        </div>

        {/* Action Bar */}
        <div className={`flex items-center justify-between border-t pt-4 mt-2 ${isPinned ? 'border-coffee-200 dark:border-coffee-700' : 'border-coffee-100 dark:border-coffee-800'}`}>
