        {followers.length > 0 ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {followers.map((follower, index) => (
                    <motion.div
                        key={follower.id}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: index * 0.05 }}
                        className="bg-coffee-50 dark:bg-coffee-900 rounded-xl p-6 border border-coffee-100 dark:border-coffee-800 hover:shadow-lg hover:-translate-y-1 transition-all group"
                    >
                        <div className="flex items-start gap-4">
                             <div className="relative">
                                <img 
                                    src={follower.avatar_url} 
                                    alt={follower.login}
                                    className="w-16 h-16 rounded-full border-2 border-coffee-200 dark:border-coffee-700 object-cover" 
                                />
                                <div className="absolute -bottom-1 -right-1 bg-white dark:bg-coffee-800 rounded-full p-1 shadow-sm">
                                    <Users size={12} className="text-coffee-500" />
                                </div>
                             </div>
                             <div className="flex-1 min-w-0">
                                 <h3 className="font-display font-bold text-lg text-coffee-900 dark:text-coffee-100 truncate">
                                     {follower.name || follower.login}
                                 </h3>
                                 <p className="text-coffee-500 dark:text-coffee-400 text-sm mb-1">@{follower.login}</p>
                                 <p className="text-coffee-600 dark:text-coffee-300 text-xs line-clamp-2 min-h-[2.5em]">
                                     {follower.bio || "No bio available."}
                                 </p>
                             </div>
                        </div>

                        <div className="mt-4 flex justify-end">
                            <a 
                                href={follower.html_url}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="flex items-center gap-1 text-xs font-bold text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white bg-white dark:bg-coffee-800 px-3 py-1.5 rounded-full shadow-sm hover:shadow-md transition-all border border-coffee-100 dark:border-coffee-700"
                            >
                                <span>Visit Profile</span>
                                <ArrowUpRight size={12} />
                            </a>
                        </div>
                    </motion.div>
                ))}
             </div>
        ) : (
            <div className="text-center py-20 text-coffee-400 dark:text-coffee-600">
                <p className="text-xl">No one has joined the coffee club yet.</p>
            </div>
        )}
      </div>
    </section>
  );
};

export default FollowersList;

import React from 'react';
import { Coffee, Github, Home, Package, Sun, Moon, Volume2, VolumeX, Users } from 'lucide-react';
import { GitHubUser } from '../types';
import { motion } from 'framer-motion';

interface NavbarProps {
  user: GitHubUser | null;
  isDark: boolean;
  toggleTheme: () => void;
  isPlaying: boolean;
  toggleMusic: () => void;
  currentView: 'home' | 'followers';
  setView: (view: 'home' | 'followers') => void;
}

const Navbar: React.FC<NavbarProps> = ({ user, isDark, toggleTheme, isPlaying, toggleMusic, currentView, setView }) => {
  const scrollToSection = (id: string) => {
    if (currentView !== 'home') {
        setView('home');
        // Allow render to happen then scroll
        setTimeout(() => {
             const element = document.getElementById(id);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    } else {
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <nav className="fixed top-0 left-0 right-0 z-40 bg-coffee-50/90 dark:bg-coffee-950/90 backdrop-blur-md border-b border-coffee-200 dark:border-coffee-800 shadow-sm transition-all duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">
          {/* Brand / Profile */}
          <div className="flex-shrink-0 flex items-center cursor-pointer group" onClick={() => scrollToSection('hero')}>
            <div className="relative">
                {user ? (
                    <img className="h-10 w-10 rounded-full border-2 border-coffee-600 dark:border-coffee-400 group-hover:scale-105 transition-transform" src={user.avatar_url} alt={user.login} />
                ) : (
                    <div className="h-10 w-10 rounded-full bg-coffee-300 animate-pulse" />
                )}
                <div className="absolute -bottom-1 -right-1 bg-white dark:bg-coffee-800 rounded-full p-0.5">
                    <Coffee size={12} className="text-coffee-700 dark:text-coffee-300" />
                </div>
            </div>
            <span className="ml-3 font-display font-bold text-lg text-coffee-800 dark:text-coffee-100 hidden sm:block">
              pro-grammer-SD
            </span>
          </div>

          {/* Controls & Links */}
          <div className="flex items-center space-x-2 sm:space-x-4">

            {/* Nav Links */}
            <div className="hidden md:flex space-x-2">
                <button 
                    onClick={() => scrollToSection('hero')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center gap-2 ${currentView === 'home' ? 'text-coffee-900 dark:text-white bg-coffee-100 dark:bg-coffee-800' : 'text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white hover:bg-coffee-100 dark:hover:bg-coffee-800'}`}
                >
                <Home size={18} />
                <span>Home</span>
                </button>
                <button 
                    onClick={() => setView('followers')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center gap-2 ${currentView === 'followers' ? 'text-coffee-900 dark:text-white bg-coffee-100 dark:bg-coffee-800' : 'text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white hover:bg-coffee-100 dark:hover:bg-coffee-800'}`}
                >
                <Users size={18} />
                <span>People</span>
                </button>
                <button 
                    onClick={() => scrollToSection('repos')}
                    className="text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white px-3 py-2 rounded-md text-sm font-medium transition-colors hover:bg-coffee-100 dark:hover:bg-coffee-800 flex items-center gap-2"
                >
                <Package size={18} />
                <span>Repos</span>
                </button>
            </div>

             {/* Music Toggle */}
             <button
                onClick={toggleMusic}
                className="p-2 rounded-full text-coffee-600 dark:text-coffee-300 hover:bg-coffee-100 dark:hover:bg-coffee-800 transition-colors"
                title={isPlaying ? "Pause LoFi" : "Play LoFi"}
            >
                {isPlaying ? <Volume2 size={20} className="animate-pulse" /> : <VolumeX size={20} />}
            </button>

            {/* Theme Toggle */}
            <button
                onClick={toggleTheme}
                className="p-2 rounded-full text-coffee-600 dark:text-coffee-300 hover:bg-coffee-100 dark:hover:bg-coffee-800 transition-colors relative overflow-hidden"
                title="Toggle Roast"
            >
                <motion.div
                    initial={false}
                    animate={{ rotate: isDark ? 180 : 0 }}
                    transition={{ duration: 0.5 }}
                >
                    {isDark ? <Sun size={20} /> : <Moon size={20} />}
                </motion.div>
            </button>

             <a 
                href="https://github.com/pro-grammer-SD" 
                target="_blank" 
                rel="noreferrer"
                className="text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white px-3 py-2 rounded-md transition-colors hover:bg-coffee-100 dark:hover:bg-coffee-800 flex items-center gap-2"
            >
              <Github size={18} />
              <span className="hidden sm:inline">GitHub</span>
            </a>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useEffect, useState } from 'react';
import { motion, useAnimation, AnimatePresence } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import { ChevronDown, ChevronUp } from 'lucide-react';
import { GitHubUser } from '../types';
