import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { fetchProfile, fetchRepos, fetchPinnedRepos, fetchFollowers } from './services/githubService';
import { GitHubUser, GitHubRepo } from './types';
import CoffeeLoader from './components/CoffeeLoader';
import Navbar from './components/Navbar';
import ProfileHero from './components/ProfileHero';
import RepoGrid from './components/RepoGrid';
import FollowersList from './components/FollowersList';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<GitHubUser | null>(null);
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [pinnedRepos, setPinnedRepos] = useState<GitHubRepo[]>([]);
  const [followers, setFollowers] = useState<GitHubUser[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Navigation State
  const [currentView, setCurrentView] = useState<'home' | 'followers'>('home');

  // Theme State
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    // Check system preference
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
        setIsDark(true);
    }
  }, []);

  useEffect(() => {
    if (isDark) {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  useEffect(() => {
    const init = async () => {
      // Minimum loading time of 4 seconds as requested for the experience
      const minLoadTime = new Promise(resolve => setTimeout(resolve, 4000));

      try {
        const [userData, reposData, pinnedData, followersData] = await Promise.all([
          fetchProfile(),
          fetchRepos(),
          fetchPinnedRepos(),
          fetchFollowers(),
          minLoadTime
        ]);

        setUser(userData);
        setRepos(reposData);
        setPinnedRepos(pinnedData);
        setFollowers(followersData);
      } catch (err) {
        console.error("Error loading profile:", err);
        setError("Could not load GitHub data. Rate limit might be exceeded.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, []);

  const toggleTheme = () => setIsDark(!isDark);

  return (
    <>
      <AnimatePresence mode="wait">
        {loading && (
            <motion.div 
                key="loader"
                exit={{ opacity: 0, y: -20 }}
                transition={{ duration: 0.5 }}
                className="fixed inset-0 z-50 bg-coffee-50 dark:bg-coffee-950"
            >
                <CoffeeLoader />
            </motion.div>
        )}
      </AnimatePresence>

      {!loading && !error && user && (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.8 }}
            className="min-h-screen flex flex-col bg-coffee-50 dark:bg-coffee-950 transition-colors duration-500"
        >
          <Navbar 
            user={user} 
            isDark={isDark} 
            toggleTheme={toggleTheme} 
            currentView={currentView}
            setView={setCurrentView}
          />

          <main className="flex-grow">
            <ProfileHero user={user} setView={setCurrentView} />

            <AnimatePresence mode="wait">
                {currentView === 'home' ? (
                    <motion.div 
                        key="home"
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: -20 }}
                        transition={{ duration: 0.3 }}
                    >
                        <RepoGrid repos={repos} pinnedRepos={pinnedRepos} />
                    </motion.div>
                ) : (
                    <motion.div 
                        key="followers"
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: 20 }}
                        transition={{ duration: 0.3 }}
                    >
                        <FollowersList followers={followers} />
                    </motion.div>
                )}
            </AnimatePresence>
          </main>

          <footer className="bg-white dark:bg-coffee-900 py-8 border-t border-coffee-200 dark:border-coffee-800 mt-auto transition-colors duration-500">
            <div className="max-w-7xl mx-auto px-4 text-center text-coffee-500 dark:text-coffee-400 text-sm">
              <p>&copy; {new Date().getFullYear()} {user.name}. Brewed with React & Coffee.</p>
            </div>
          </footer>
        </motion.div>
      )}

      {error && !loading && (
        <div className="min-h-screen flex flex-col items-center justify-center p-4 text-center bg-coffee-50 dark:bg-coffee-950 text-coffee-900 dark:text-coffee-100">
            <div className="text-6xl mb-4">☕💔</div>
            <h1 className="text-2xl font-bold mb-2">Out of Coffee Beans</h1>
            <p className="text-coffee-600 dark:text-coffee-400">{error}</p>
            <p className="text-xs text-coffee-400 dark:text-coffee-500 mt-4">Try refreshing in a few minutes.</p>
        </div>
      )}
    </>
  );
};

export default App;

import React from 'react';
import { Coffee, Github, Home, Package, Sun, Moon, Users } from 'lucide-react';
import { GitHubUser } from '../types';
import { motion } from 'framer-motion';

interface NavbarProps {
  user: GitHubUser | null;
  isDark: boolean;
  toggleTheme: () => void;
  currentView: 'home' | 'followers';
  setView: (view: 'home' | 'followers') => void;
}

const Navbar: React.FC<NavbarProps> = ({ user, isDark, toggleTheme, currentView, setView }) => {
  const scrollToSection = (id: string) => {
    if (currentView !== 'home') {
        setView('home');
        // Allow render to happen then scroll
        setTimeout(() => {
             const element = document.getElementById(id);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    } else {
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <nav className="fixed top-0 left-0 right-0 z-40 bg-coffee-50/90 dark:bg-coffee-950/90 backdrop-blur-md border-b border-coffee-200 dark:border-coffee-800 shadow-sm transition-all duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">
          {/* Brand / Profile */}
          <div className="flex-shrink-0 flex items-center cursor-pointer group" onClick={() => scrollToSection('hero')}>
            <div className="relative">
                {user ? (
                    <img className="h-10 w-10 rounded-full border-2 border-coffee-600 dark:border-coffee-400 group-hover:scale-105 transition-transform" src={user.avatar_url} alt={user.login} />
                ) : (
                    <div className="h-10 w-10 rounded-full bg-coffee-300 animate-pulse" />
                )}
                <div className="absolute -bottom-1 -right-1 bg-white dark:bg-coffee-800 rounded-full p-0.5">
                    <Coffee size={12} className="text-coffee-700 dark:text-coffee-300" />
                </div>
            </div>
            <span className="ml-3 font-display font-bold text-lg text-coffee-800 dark:text-coffee-100 hidden sm:block">
              pro-grammer-SD
            </span>
          </div>

          {/* Controls & Links */}
          <div className="flex items-center space-x-2 sm:space-x-4">

            {/* Nav Links */}
            <div className="hidden md:flex space-x-2">
                <button 
                    onClick={() => scrollToSection('hero')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center gap-2 ${currentView === 'home' ? 'text-coffee-900 dark:text-white bg-coffee-100 dark:bg-coffee-800' : 'text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white hover:bg-coffee-100 dark:hover:bg-coffee-800'}`}
                >
                <Home size={18} />
                <span>Home</span>
                </button>
                <button 
                    onClick={() => setView('followers')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center gap-2 ${currentView === 'followers' ? 'text-coffee-900 dark:text-white bg-coffee-100 dark:bg-coffee-800' : 'text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white hover:bg-coffee-100 dark:hover:bg-coffee-800'}`}
                >
                <Users size={18} />
                <span>People</span>
                </button>
                <button 
                    onClick={() => scrollToSection('repos')}
                    className="text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white px-3 py-2 rounded-md text-sm font-medium transition-colors hover:bg-coffee-100 dark:hover:bg-coffee-800 flex items-center gap-2"
                >
                <Package size={18} />
                <span>Repos</span>
                </button>
            </div>

            {/* Theme Toggle */}
            <button
                onClick={toggleTheme}
                className="p-2 rounded-full text-coffee-600 dark:text-coffee-300 hover:bg-coffee-100 dark:hover:bg-coffee-800 transition-colors relative overflow-hidden"
                title="Toggle Roast"
            >
                <motion.div
                    initial={false}
                    animate={{ rotate: isDark ? 180 : 0 }}
                    transition={{ duration: 0.5 }}
                >
                    {isDark ? <Sun size={20} /> : <Moon size={20} />}
                </motion.div>
            </button>

             <a 
                href="https://github.com/pro-grammer-SD" 
                target="_blank" 
                rel="noreferrer"
                className="text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white px-3 py-2 rounded-md transition-colors hover:bg-coffee-100 dark:hover:bg-coffee-800 flex items-center gap-2"
            >
              <Github size={18} />
              <span className="hidden sm:inline">GitHub</span>
            </a>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Coffee, Github, Home, Package, Sun, Moon, Users, Menu, X } from 'lucide-react';
import { GitHubUser } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

interface NavbarProps {
  user: GitHubUser | null;
  isDark: boolean;
  toggleTheme: () => void;
  currentView: 'home' | 'followers';
  setView: (view: 'home' | 'followers') => void;
}

const Navbar: React.FC<NavbarProps> = ({ user, isDark, toggleTheme, currentView, setView }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const scrollToSection = (id: string) => {
    setIsMobileMenuOpen(false); // Close mobile menu if open
    if (currentView !== 'home') {
        setView('home');
        // Allow render to happen then scroll
        setTimeout(() => {
             const element = document.getElementById(id);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    } else {
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleSetView = (view: 'home' | 'followers') => {
      setView(view);
      setIsMobileMenuOpen(false);
  };

  const navLinks = [
      { id: 'hero', label: 'Home', icon: Home, action: () => scrollToSection('hero'), active: currentView === 'home' },
      { id: 'followers', label: 'People', icon: Users, action: () => handleSetView('followers'), active: currentView === 'followers' },
      { id: 'repos', label: 'Repos', icon: Package, action: () => scrollToSection('repos'), active: false },
  ];

  return (
    <nav className="fixed top-0 left-0 right-0 z-40 bg-coffee-50/90 dark:bg-coffee-950/90 backdrop-blur-md border-b border-coffee-200 dark:border-coffee-800 shadow-sm transition-all duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">
          {/* Brand / Profile */}
          <div className="flex-shrink-0 flex items-center cursor-pointer group" onClick={() => scrollToSection('hero')}>
            <div className="relative">
                {user ? (
                    <img className="h-8 w-8 sm:h-10 sm:w-10 rounded-full border-2 border-coffee-600 dark:border-coffee-400 group-hover:scale-105 transition-transform" src={user.avatar_url} alt={user.login} />
                ) : (
                    <div className="h-8 w-8 sm:h-10 sm:w-10 rounded-full bg-coffee-300 animate-pulse" />
                )}
                <div className="absolute -bottom-1 -right-1 bg-white dark:bg-coffee-800 rounded-full p-0.5">
                    <Coffee size={10} className="text-coffee-700 dark:text-coffee-300 sm:w-3 sm:h-3" />
                </div>
            </div>
            <span className="ml-2 sm:ml-3 font-display font-bold text-base sm:text-lg text-coffee-800 dark:text-coffee-100 block">
              pro-grammer-SD
            </span>
          </div>

          {/* Desktop Controls & Links */}
          <div className="flex items-center gap-2 sm:gap-4">

            {/* Desktop Nav Links */}
            <div className="hidden md:flex space-x-2">
                {navLinks.map((link) => (
                    <button 
                        key={link.label}
                        onClick={link.action}
                        className={`px-3 py-2 rounded-md text-sm font-medium transition-colors flex items-center gap-2 ${link.active ? 'text-coffee-900 dark:text-white bg-coffee-100 dark:bg-coffee-800' : 'text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white hover:bg-coffee-100 dark:hover:bg-coffee-800'}`}
                    >
                    <link.icon size={18} />
                    <span>{link.label}</span>
                    </button>
                ))}
            </div>

            {/* Theme Toggle */}
            <button
                onClick={toggleTheme}
                className="p-2 rounded-full text-coffee-600 dark:text-coffee-300 hover:bg-coffee-100 dark:hover:bg-coffee-800 transition-colors relative overflow-hidden"
                title="Toggle Roast"
            >
                <motion.div
                    initial={false}
                    animate={{ rotate: isDark ? 180 : 0 }}
                    transition={{ duration: 0.5 }}
                >
                    {isDark ? <Sun size={20} /> : <Moon size={20} />}
                </motion.div>
            </button>

             <a 
                href="https://github.com/pro-grammer-SD" 
                target="_blank" 
                rel="noreferrer"
                className="text-coffee-600 dark:text-coffee-300 hover:text-coffee-900 dark:hover:text-white px-2 sm:px-3 py-2 rounded-md transition-colors hover:bg-coffee-100 dark:hover:bg-coffee-800 flex items-center gap-2"
            >
              <Github size={20} />
              <span className="hidden sm:inline">GitHub</span>
            </a>

            {/* Mobile Menu Button */}
            <button
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                className="md:hidden p-2 text-coffee-600 dark:text-coffee-300 hover:bg-coffee-100 dark:hover:bg-coffee-800 rounded-md transition-colors"
                aria-label="Toggle Menu"
            >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      <AnimatePresence>
        {isMobileMenuOpen && (
            <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                transition={{ duration: 0.2 }}
                className="md:hidden bg-coffee-50/95 dark:bg-coffee-950/95 backdrop-blur-xl border-t border-coffee-200 dark:border-coffee-800 overflow-hidden"
            >
                <div className="px-4 pt-2 pb-6 space-y-2 shadow-inner">
                    {navLinks.map((link) => (
                        <button
                            key={link.label}
                            onClick={link.action}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-base font-medium transition-colors ${
                                link.active 
                                ? 'bg-coffee-100 dark:bg-coffee-800 text-coffee-900 dark:text-coffee-100' 
                                : 'text-coffee-600 dark:text-coffee-400 hover:bg-coffee-100/50 dark:hover:bg-coffee-800/50'
                            }`}
                        >
                            <link.icon size={20} />
                            {link.label}
                        </button>
                    ))}
                </div>
            </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;

import React, { useEffect, useState } from 'react';
import { motion, useAnimation, AnimatePresence } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import { ChevronDown, ChevronUp } from 'lucide-react';
import { GitHubUser } from '../types';
import { fetchReadme } from '../services/githubService';

interface ProfileHeroProps {
  user: GitHubUser;
  setView: (view: 'home' | 'followers') => void;
}

const ProfileHero: React.FC<ProfileHeroProps> = ({ user, setView }) => {
  const [profileReadme, setProfileReadme] = useState<string | null>(null);
  const [isReadmeExpanded, setIsReadmeExpanded] = useState(false);
  const controls = useAnimation();
  const [easterEggActive, setEasterEggActive] = useState(false);

  useEffect(() => {
    const loadProfileReadme = async () => {
      const content = await fetchReadme(user.login, 'main');
      if (content) setProfileReadme(content);
      else {
           const contentMaster = await fetchReadme(user.login, 'master');
           setProfileReadme(contentMaster);
      }
    };
    loadProfileReadme();
  }, [user.login]);

  const triggerEasterEgg = async () => {
    if (easterEggActive) return;
    setEasterEggActive(true);

    await controls.start({
        rotate: [0, -15, 15, -15, 15, 0],
        scale: [1, 1.2, 1.2, 1.2, 1],
        transition: { duration: 0.5 }
    });

    setEasterEggActive(false);
  };

  return (
    <section id="hero" className="relative pt-24 pb-12 sm:pt-32 sm:pb-20 overflow-hidden">
      {/* Background decorations */}
      <div className="absolute top-20 right-10 w-40 h-40 sm:w-64 sm:h-64 bg-coffee-100 dark:bg-coffee-900 rounded-full blur-3xl opacity-50 -z-10 animate-pulse"></div>
      <div className="absolute bottom-10 left-10 w-32 h-32 sm:w-48 sm:h-48 bg-orange-100 dark:bg-coffee-800 rounded-full blur-3xl opacity-50 -z-10"></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row items-start gap-8 md:gap-12">

            {/* Left: Avatar & Stats */}
            <motion.div 
                initial={{ x: -50, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                transition={{ duration: 0.7 }}
                className="flex-shrink-0 text-center md:text-left sticky top-24 w-full md:w-auto flex flex-col items-center md:items-start"
            >
                {/* 3D Aesthetic Avatar Container */}
                <div className="relative group perspective-1000">
                    <motion.div
                        className="relative w-40 h-40 sm:w-56 sm:h-56 rounded-full shadow-2xl transition-all duration-500 ease-out transform-style-3d group-hover:rotate-y-12 group-hover:rotate-x-12"
                        whileHover={{ scale: 1.05 }}
                    >
                        {/* Steam Animation on Hover - Scaled for responsiveness */}
                        <div className="absolute -top-6 sm:-top-10 left-1/2 -translate-x-1/2 w-full h-full opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none">
                            <div className="absolute top-0 left-6 sm:left-10 text-2xl sm:text-4xl text-coffee-300 dark:text-coffee-600 animate-steam-1">♨️</div>
                            <div className="absolute -top-2 sm:-top-4 left-16 sm:left-24 text-xl sm:text-3xl text-coffee-300 dark:text-coffee-600 animate-steam-2">♨️</div>
                            <div className="absolute top-0 left-24 sm:left-36 text-2xl sm:text-4xl text-coffee-300 dark:text-coffee-600 animate-steam-3">♨️</div>
                        </div>

                        <img 
                            src={user.avatar_url} 
                            alt={user.name} 
                            className="w-full h-full rounded-full border-4 border-white dark:border-coffee-700 object-cover shadow-[0_20px_50px_rgba(8,112,184,0.7)] dark:shadow-[0_20px_50px_rgba(78,48,42,0.5)] bg-coffee-100"
                        />

                        {/* Coffee Mug Icon (Easter Egg Trigger) */}
                        <motion.div 
                            animate={controls}
                            onClick={triggerEasterEgg}
                            className="absolute bottom-2 right-2 sm:right-4 bg-coffee-600 hover:bg-coffee-700 text-white p-2 sm:p-2.5 rounded-full shadow-lg border-2 border-white dark:border-coffee-600 cursor-pointer transition-colors z-20"
