async function fetchData(url: string, staleData: any = null): Promise<any> {
    try {
        const response = await fetch(url, {
            headers: staleData?.etag ? { 'If-None-Match': staleData.etag } : {}
        });

        if (response.status === 304) {
            // Cache is valid.
            return staleData;
        }

        if (!response.ok) {
            if (response.status === 403) {
                // Rate limit, serve stale data if available.
                return staleData;
            }
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();
        return { data, etag: response.headers.get('etag') };

    } catch (error) {
        console.error('Fetch error:', error);
        return staleData; // Return stale data on error.
    }
}

